arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// --- ML.NET: Train and save model at startup ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");

IDataView dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: nameof(CustomerData.Churned),
        featureColumnName: "Features"));

var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
var model = pipeline.Fit(split.TrainSet);

var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions,
    labelColumnName: nameof(CustomerData.Churned));

Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                  $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

mlContext.Model.Save(model, dataView.Schema, modelPath);

// --- Register PredictionEnginePool for thread-safe web usage ---
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "ChurnPredictor API — POST /predict with customer JSON");

app.MapPost("/predict", (CustomerData customer,
    PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(customer);
    return Results.Ok(new
    {
        Churned = prediction.PredictedLabel,
        Probability = prediction.Probability,
        Score = prediction.Score
    });
});

app.Run();

// --- Data models ---

public class CustomerData
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    [ColumnName("Churned")]
    [BooleanLabel]
    public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

// Maps "Yes"/"No" strings to boolean for the label column
[AttributeUsage(AttributeTargets.Property)]
public class BooleanLabelAttribute : Attribute { }

